36	struct XorshiftRNG {
37	    uint64_t x;
38	    XorshiftRNG() : x(std::chrono::steady_clock::now().time_since_epoch().count()) {}
39	    
40	    uint64_t next() {
41	        x ^= x << 13;
42	        x ^= x >> 7;
43	        x ^= x << 17;
44	        return x;
45	    }
46	    
47	    int uniform_int(int min_val, int max_val) {
48	        if (min_val > max_val) return min_val; 
49	        if (min_val == max_val) return min_val;
50	        uint64_t range = static_cast<uint64_t>(max_val) - min_val + 1;
51	        return min_val + static_cast<int>(next() % range);
52	    }
53	};
