319	char decide_tilt_direction_logic(const GameState& current_gs_after_placement) {
320	    double best_overall_eval = std::numeric_limits<double>::lowest();
321	    int best_dir_idx = 0; 
322	
323	    int turn_T_for_lookahead_base = current_gs_after_placement.turn_num_1_indexed;
324	
325	    for (int i = 0; i < NUM_DIRECTIONS; ++i) { 
326	        GameState gs_after_tilt_T = current_gs_after_placement; 
327	        gs_after_tilt_T.apply_tilt(i); 
328	        
329	        double current_tilt_eval_for_dir_i = eval_lookahead(gs_after_tilt_T, turn_T_for_lookahead_base, MAX_LOOKAHEAD_DEPTH);
330	        
331	        if (current_tilt_eval_for_dir_i > best_overall_eval) {
332	            best_overall_eval = current_tilt_eval_for_dir_i;
333	            best_dir_idx = i;
334	        }
335	    }
336	    return DIR_CHARS[best_dir_idx];
337	}
