const char DIR_CHARS[] = {'F', 'B', 'L', 'R'};
const int NUM_DIRECTIONS = 4;

std::array<int, NUM_TURNS> G_FLAVOR_SEQUENCE;

struct GameState {
    std::array<std::array<int, GRID_SIZE>, GRID_SIZE> board;
    int num_candies;

    GameState() : num_candies(0) {
        for (int i = 0; i < GRID_SIZE; ++i)
            board[i].fill(0);
    }

    void place_candy(int r, int c, int flavor) {
        board[r][c] = flavor;
        num_candies++;
    }

    std::pair<int, int> find_pth_empty_cell(int p) const {
        int count = 0;
        for (int r = 0; r < GRID_SIZE; ++r)
            for (int c = 0; c < GRID_SIZE; ++c)
                if (board[r][c] == 0) {
                    count++;
                    if (count == p) return {r, c};
                }
        return {-1, -1};
    }

    int count_empty_cells() const {
        return GRID_SIZE * GRID_SIZE - num_candies;
    }

    void apply_tilt(int dir_idx) {
        if (dir_idx == 0) { // F (Up)
            for (int c = 0; c < GRID_SIZE; ++c) {
                int wr = 0;
                for (int r = 0; r < GRID_SIZE; ++r)
                    if (board[r][c] != 0) {
                        if (r != wr) { board[wr][c] = board[r][c]; board[r][c] = 0; }
                        wr++;
                    }
            }
        } else if (dir_idx == 1) { // B (Down)
            for (int c = 0; c < GRID_SIZE; ++c) {
                int wr = GRID_SIZE - 1;
                for (int r = GRID_SIZE - 1; r >= 0; --r)
                    if (board[r][c] != 0) {
                        if (r != wr) { board[wr][c] = board[r][c]; board[r][c] = 0; }
                        wr--;
                    }
            }
        } else if (dir_idx == 2) { // L (Left)
            for (int r = 0; r < GRID_SIZE; ++r) {
                int wc = 0;
                for (int c = 0; c < GRID_SIZE; ++c)
                    if (board[r][c] != 0) {
                        if (c != wc) { board[r][wc] = board[r][c]; board[r][c] = 0; }
                        wc++;
                    }
            }
        } else { // R (Right)
            for (int r = 0; r < GRID_SIZE; ++r) {
                int wc = GRID_SIZE - 1;
                for (int c = GRID_SIZE - 1; c >= 0; --c)
                    if (board[r][c] != 0) {
                        if (c != wc) { board[r][wc] = board[r][c]; board[r][c] = 0; }
                        wc--;
                    }
            }
        }
    }

    long long compute_score_numerator() const {
        std::array<std::array<bool, GRID_SIZE>, GRID_SIZE> visited;
        for (int i = 0; i < GRID_SIZE; ++i) visited[i].fill(false);

        long long total = 0;
        std::array<std::pair<int,int>, 100> q;

        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] != 0 && !visited[r][c]) {
                    int flavor = board[r][c];
                    int size = 0;
                    int head = 0, tail = 0;
                    q[tail++] = {r, c};
                    visited[r][c] = true;
                    while (head < tail) {
                        auto [cr, cc] = q[head++];
                        size++;
                        for (int d = 0; d < 4; ++d) {
                            int nr = cr + DR[d], nc = cc + DC[d];
                            if (nr >= 0 && nr < GRID_SIZE && nc >= 0 && nc < GRID_SIZE &&
                                !visited[nr][nc] && board[nr][nc] == flavor) {
                                visited[nr][nc] = true;
                                q[tail++] = {nr, nc};
                            }
                        }
                    }
                    total += (long long)size * size;
                }
            }
        }
        return total;
    }

    int count_same_flavor_adj_pairs() const {
        int count = 0;
        for (int r = 0; r < GRID_SIZE; ++r)
            for (int c = 0; c < GRID_SIZE; ++c)
                if (board[r][c] != 0) {
                    if (r + 1 < GRID_SIZE && board[r+1][c] == board[r][c]) count++;
                    if (c + 1 < GRID_SIZE && board[r][c+1] == board[r][c]) count++;
                }
        return count;
    }

    int count_diff_flavor_adj_pairs() const {
        int count = 0;
        for (int r = 0; r < GRID_SIZE; ++r)
            for (int c = 0; c < GRID_SIZE; ++c)
                if (board[r][c] != 0) {
                    if (r + 1 < GRID_SIZE && board[r+1][c] != 0 && board[r+1][c] != board[r][c]) count++;
                    if (c + 1 < GRID_SIZE && board[r][c+1] != 0 && board[r][c+1] != board[r][c]) count++;
                }
        return count;
    }

    int count_future_potential(int next_flavor) const {
        if (next_flavor == 0) return 0;
        int count = 0;
        for (int r = 0; r < GRID_SIZE; ++r)
            for (int c = 0; c < GRID_SIZE; ++c)
                if (board[r][c] == 0) {
                    bool adj_to_same = false;
                    for (int d = 0; d < 4; ++d) {
                        int nr = r + DR[d], nc = c + DC[d];
                        if (nr >= 0 && nr < GRID_SIZE && nc >= 0 && nc < GRID_SIZE &&
                            board[nr][nc] == next_flavor) {
                            adj_to_same = true;
                            break;
                        }
                    }
                    if (adj_to_same) count++;
                }
        return count;
    }

    int count_isolated_candies() const {
        int count = 0;
        for (int r = 0; r < GRID_SIZE; ++r)
            for (int c = 0; c < GRID_SIZE; ++c)
                if (board[r][c] != 0) {
                    bool has_same_neighbor = false;
                    for (int d = 0; d < 4; ++d) {
                        int nr = r + DR[d], nc = c + DC[d];
                        if (nr >= 0 && nr < GRID_SIZE && nc >= 0 && nc < GRID_SIZE &&
                            board[nr][nc] == board[r][c]) {
                            has_same_neighbor = true;
                            break;
                        }
                    }
                    if (!has_same_neighbor) count++;
                }
        return count;
    }

    double evaluate(int turn, int next_flavor) const {
        long long conn_score = compute_score_numerator();
        int same_adj = count_same_flavor_adj_pairs();
        int diff_adj = count_diff_flavor_adj_pairs();
        int future_pot = count_future_potential(next_flavor);
        int isolated = count_isolated_candies();

        double progress = (double)turn / NUM_TURNS;

        // Weights shift over time: early game favors future potential and reducing isolation,
        // late game favors actual connectivity score
        double w_conn = 1.0 + 4.0 * progress;
        double w_same_adj = 3.0;
        double w_diff_adj = -1.5;
        double w_future = 2.5 * (1.0 - progress);
        double w_isolated = -2.0;

        return w_conn * conn_score +
               w_same_adj * same_adj +
               w_diff_adj * diff_adj +
               w_future * future_pot +
               w_isolated * isolated;
    }
};

