    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    for (int t = 0; t < NUM_TURNS; ++t)
        std::cin >> G_FLAVOR_SEQUENCE[t];

    GameState gs;
    for (int t = 0; t < NUM_TURNS; ++t) {
        int p;
