        int next_flavor = (t + 1 < NUM_TURNS) ? G_FLAVOR_SEQUENCE[t + 1] : 0;

        double best_eval = -1e18;
        int best_dir = 0;

        for (int d = 0; d < NUM_DIRECTIONS; ++d) {
            GameState tmp = gs;
            tmp.apply_tilt(d);
            double eval = tmp.evaluate(t + 1, next_flavor);
            if (eval > best_eval) {
                best_eval = eval;
                best_dir = d;
            }
        }

        std::cout << DIR_CHARS[best_dir] << std::endl;
        gs.apply_tilt(best_dir);
    }

    return 0;
}
