                double best_ev = -1e18;
                int best_d = 0;
                for (int dd = 0; dd < 4; ++dd) {
                    Board tmp = sim;
                    tmp.tilt(dd);
                    // Use fast adjacency for inner simulation
                    double ev = tmp.adjacency_score();
                    if (ev > best_ev) { best_ev = ev; best_d = dd; }
                }
                sim.tilt(best_d);
