    return (double)conn + 0.5 * adj;
}

// Monte Carlo lookahead: for each direction, simulate future placements
// and pick optimal tilts greedily, return average final eval
int choose_direction_mc(const Board& gs, int turn) {
    auto start = std::chrono::steady_clock::now();
