        if (round >= 50) break; // safety cap
    }

    int best_dir = 0;
    double best_avg = -1e18;
    for (int d = 0; d < 4; ++d) {
        if (dir_counts[d] > 0) {
            double avg = dir_scores[d] / dir_counts[d];
            if (avg > best_avg) { best_avg = avg; best_dir = d; }
        }
    }
    return best_dir;
}

int main() {
