const int DC[] = {0, 0, -1, 1};
const char DIR_CHARS[] = {'F', 'B', 'L', 'R'};
const int NUM_DIRECTIONS = 4;

std::array<int, NUM_TURNS> G_FLAVOR_SEQUENCE;

struct XorshiftRNG {
    uint64_t x;
    XorshiftRNG() : x(88172645463325252ULL ^ std::chrono::steady_clock::now().time_since_epoch().count()) {}
    uint64_t next() { x ^= x << 13; x ^= x >> 7; x ^= x << 17; return x; }
    int uniform_int(int lo, int hi) {
        return lo + (int)(next() % (uint64_t)(hi - lo + 1));
    }
};
XorshiftRNG rng;

struct Board {
    std::array<std::array<int, GRID_SIZE>, GRID_SIZE> grid;
    int num_candies;

    Board() : num_candies(0) { for (auto& row : grid) row.fill(0); }

    void place(int r, int c, int fl) { grid[r][c] = fl; num_candies++; }

    std::pair<int,int> find_pth_empty(int p) const {
        int cnt = 0;
        for (int r = 0; r < GRID_SIZE; ++r)
            for (int c = 0; c < GRID_SIZE; ++c)
                if (!grid[r][c] && ++cnt == p) return {r, c};
        return {-1,-1};
    }

    int count_empty() const { return GRID_SIZE*GRID_SIZE - num_candies; }

    void tilt(int d) {
        if (d == 0) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                int wr = 0;
                for (int r = 0; r < GRID_SIZE; ++r)
                    if (grid[r][c]) { if (r != wr) { grid[wr][c] = grid[r][c]; grid[r][c] = 0; } wr++; }
            }
        } else if (d == 1) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                int wr = GRID_SIZE-1;
                for (int r = GRID_SIZE-1; r >= 0; --r)
                    if (grid[r][c]) { if (r != wr) { grid[wr][c] = grid[r][c]; grid[r][c] = 0; } wr--; }
            }
        } else if (d == 2) {
            for (int r = 0; r < GRID_SIZE; ++r) {
                int wc = 0;
                for (int c = 0; c < GRID_SIZE; ++c)
                    if (grid[r][c]) { if (c != wc) { grid[r][wc] = grid[r][c]; grid[r][c] = 0; } wc++; }
            }
        } else {
            for (int r = 0; r < GRID_SIZE; ++r) {
                int wc = GRID_SIZE-1;
                for (int c = GRID_SIZE-1; c >= 0; --c)
                    if (grid[r][c]) { if (c != wc) { grid[r][wc] = grid[r][c]; grid[r][c] = 0; } wc--; }
            }
        }
    }

    long long connectivity_score() const {
        std::array<std::array<bool, GRID_SIZE>, GRID_SIZE> visited;
        for (auto& row : visited) row.fill(false);
        long long total = 0;
        std::array<std::pair<int,int>, 100> q;
        for (int r = 0; r < GRID_SIZE; ++r)
            for (int c = 0; c < GRID_SIZE; ++c)
                if (grid[r][c] && !visited[r][c]) {
                    int fl = grid[r][c], sz = 0, h = 0, t = 0;
                    q[t++] = {r, c}; visited[r][c] = true;
                    while (h < t) {
                        auto [cr, cc] = q[h++]; sz++;
                        for (int d = 0; d < 4; ++d) {
                            int nr = cr+DR[d], nc = cc+DC[d];
                            if (nr>=0 && nr<GRID_SIZE && nc>=0 && nc<GRID_SIZE && !visited[nr][nc] && grid[nr][nc]==fl) {
                                visited[nr][nc] = true; q[t++] = {nr, nc};
                            }
                        }
                    }
                    total += (long long)sz * sz;
                }
        return total;
    }

    int adjacency_score() const {
        int s = 0;
        for (int r = 0; r < GRID_SIZE; ++r)
            for (int c = 0; c < GRID_SIZE; ++c)
                if (grid[r][c]) {
                    if (r+1<GRID_SIZE && grid[r+1][c]==grid[r][c]) s++;
                    if (c+1<GRID_SIZE && grid[r][c+1]==grid[r][c]) s++;
                }
        return s;
    }

    double fast_eval() const {
        return (double)connectivity_score() + 0.3 * adjacency_score();
    }
};

auto G_START_TIME = std::chrono::steady_clock::now();

double elapsed_ms() {
    return std::chrono::duration<double, std::milli>(
        std::chrono::steady_clock::now() - G_START_TIME).count();
}

int choose_direction(const Board& gs, int turn) {
    // Total time budget: 1850ms
    double total_budget_ms = 1850.0;
    double elapsed = elapsed_ms();
    double remaining_ms = total_budget_ms - elapsed;
    int remaining_turns = NUM_TURNS - turn + 1;
    double per_turn_budget = remaining_ms / remaining_turns;
    if (per_turn_budget < 0.5) per_turn_budget = 0.5;

    auto turn_start = std::chrono::steady_clock::now();

    int depth;
    if (turn <= 40) depth = 3;
    else if (turn <= 75) depth = 3;
    else depth = 2;

    double dir_scores[4] = {0, 0, 0, 0};
    int dir_counts[4] = {0, 0, 0, 0};

    // Monte Carlo sampling with time budget
    bool done = false;
    int total_samples = 0;
    while (!done) {
        for (int d = 0; d < 4 && !done; ++d) {
            Board after = gs;
            after.tilt(d);

            // Simulate future with greedy tilt at each step
            Board sim = after;
            int sim_turn = turn;
            for (int step = 0; step < depth && sim_turn < NUM_TURNS; ++step) {
                int empty = sim.count_empty();
                if (empty == 0) break;
                int pos = rng.uniform_int(1, empty);
                auto [pr, pc] = sim.find_pth_empty(pos);
                sim.place(pr, pc, G_FLAVOR_SEQUENCE[sim_turn]);
                sim_turn++;

                // Greedy tilt using full connectivity + adjacency
                double best_ev = -1e18;
                int best_d = 0;
                for (int dd = 0; dd < 4; ++dd) {
                    Board tmp = sim;
                    tmp.tilt(dd);
                    double ev = tmp.fast_eval();
                    if (ev > best_ev) { best_ev = ev; best_d = dd; }
                }
                sim.tilt(best_d);
            }

            dir_scores[d] += sim.fast_eval();
            dir_counts[d]++;
            total_samples++;

            auto now = std::chrono::steady_clock::now();
            double turn_elapsed = std::chrono::duration<double, std::milli>(now - turn_start).count();
            if (turn_elapsed > per_turn_budget) { done = true; }
        }
        if (total_samples >= 200) break; // safety cap
    }

    int best_dir = 0;
    double best_avg = -1e18;
    for (int d = 0; d < 4; ++d) {
        if (dir_counts[d] > 0) {
            double avg = dir_scores[d] / dir_counts[d];
            if (avg > best_avg) { best_avg = avg; best_dir = d; }
        }
    }
    return best_dir;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    for (int t = 0; t < NUM_TURNS; ++t)
        std::cin >> G_FLAVOR_SEQUENCE[t];

    G_START_TIME = std::chrono::steady_clock::now();

    Board gs;
    for (int t = 0; t < NUM_TURNS; ++t) {
        int p;
        std::cin >> p;
        auto [r, c] = gs.find_pth_empty(p);
        gs.place(r, c, G_FLAVOR_SEQUENCE[t]);

        int dir = choose_direction(gs, t + 1);
        std::cout << DIR_CHARS[dir] << std::endl;
        gs.tilt(dir);
    }

    return 0;
}
